import{_ as t,o as a,c as d,ag as o}from"./chunks/framework.DTiDeF2Q.js";const m=JSON.parse('{"title":"Alias Chmod: atajos de permisos para el shell | Dotfiles (ES)","titleTemplate":":title","description":"Simplifica la gestión de permisos con alias chmod. Atajos para patrones comunes como 755, 644 y más.","frontmatter":{"title":"Alias Chmod: atajos de permisos para el shell","description":"Simplifica la gestión de permisos con alias chmod. Atajos para patrones comunes como 755, 644 y más.","lang":"es-ES","author":"Sebastien Rousseau","lastUpdated":true,"image":"/logo.png","imageAlt":"Alias Chmod: atajos de permisos para el shell preview","canonical":"/es/aliases/chmod/","robots":"index, follow","draft":false,"noindex":false,"sitemap":true,"breadcrumbTitle":"Alias Chmod: atajos de permisos para el shell","pageType":"docs","schemaType":"WebPage","metaTitle":"Alias Chmod | Dotfiles","permalink":"/es/aliases/chmod/","sidebar":true,"meta":[{"name":"keywords","content":"alias chmod, permisos de archivos, atajos shell, dotfiles, permisos unix"},{"name":"twitter:card","content":"summary"},{"name":"twitter:title","content":"Alias Chmod | Dotfiles"},{"name":"twitter:description","content":"Simplifica la gestión de permisos con alias chmod."},{"name":"og:title","content":"Alias Chmod | Dotfiles"},{"name":"og:description","content":"Simplifica la gestión de permisos con alias chmod."},{"name":"og:image:alt","content":"Dotfiles - Diseñado para tu vida en el shell"},{"name":"og:locale","content":"es_ES"}]},"headers":[],"relativePath":"es/aliases/chmod/index.md","filePath":"es/aliases/chmod/index.md","lastUpdated":1773010926000}'),r={name:"es/aliases/chmod/index.md"};function i(s,e,c,l,p,n){return a(),d("div",null,[...e[0]||(e[0]=[o('<h1 id="alias-chmod" tabindex="-1">Alias Chmod <a class="header-anchor" href="#alias-chmod" aria-label="Permalink to &quot;Alias Chmod&quot;">​</a></h1><p>Atajos para gestionar permisos de archivos y directorios.</p><p><img src="https://kura.pro/dotfiles/v2/images/titles/title-dotfiles.svg" alt="Dotfiles banner"></p><h2 id="descubrir" tabindex="-1">Descubrir <a class="header-anchor" href="#descubrir" aria-label="Permalink to &quot;Descubrir&quot;">​</a></h2><p>Los alias chmod ofrecen una forma rápida de gestionar permisos desde la línea de comandos. En lugar de memorizar códigos numéricos, usa alias intuitivos como <code>chmod_755</code> o <code>chmod_u+x</code> para establecer el acceso necesario.</p><p>Estos alias se definen en <code>chmod.aliases.sh</code> y se cargan automáticamente por chezmoi.</p><h2 id="referencia" tabindex="-1">Referencia <a class="header-anchor" href="#referencia" aria-label="Permalink to &quot;Referencia&quot;">​</a></h2><h3 id="alias-de-permisos-comunes" tabindex="-1">Alias de permisos comunes <a class="header-anchor" href="#alias-de-permisos-comunes" aria-label="Permalink to &quot;Alias de permisos comunes&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Permisos</th><th>Descripción</th></tr></thead><tbody><tr><td><code>chmod_000</code></td><td><code>----------</code></td><td>Sin permisos para nadie</td></tr><tr><td><code>chmod_400</code></td><td><code>r--------</code></td><td>Solo lectura para el propietario</td></tr><tr><td><code>chmod_444</code></td><td><code>r--r--r--</code></td><td>Solo lectura para todos</td></tr><tr><td><code>chmod_600</code></td><td><code>rw-------</code></td><td>Lectura/escritura para el propietario</td></tr><tr><td><code>chmod_644</code></td><td><code>rw-r--r--</code></td><td>Lectura/escritura para el propietario, lectura para otros</td></tr><tr><td><code>chmod_666</code></td><td><code>rw-rw-rw-</code></td><td>Lectura/escritura para todos</td></tr><tr><td><code>chmod_755</code></td><td><code>rwxr-xr-x</code></td><td>Total para propietario, lectura/ejecución para otros</td></tr><tr><td><code>chmod_764</code></td><td><code>rwxrw-r--</code></td><td>Total para propietario, lectura/escritura para grupo</td></tr><tr><td><code>chmod_777</code></td><td><code>rwxrwxrwx</code></td><td>Todos los permisos para todos</td></tr></tbody></table><h3 id="alias-de-permisos-del-propietario" tabindex="-1">Alias de permisos del propietario <a class="header-anchor" href="#alias-de-permisos-del-propietario" aria-label="Permalink to &quot;Alias de permisos del propietario&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th></tr></thead><tbody><tr><td><code>chmod_u+x</code></td><td>Añadir ejecución para el propietario</td></tr><tr><td><code>chmod_u-x</code></td><td>Quitar ejecución para el propietario</td></tr><tr><td><code>chmod_u+w</code></td><td>Añadir escritura para el propietario</td></tr><tr><td><code>chmod_u-w</code></td><td>Quitar escritura para el propietario</td></tr><tr><td><code>chmod_u+r</code></td><td>Añadir lectura para el propietario</td></tr><tr><td><code>chmod_u-r</code></td><td>Quitar lectura para el propietario</td></tr></tbody></table><h3 id="alias-de-permisos-del-grupo" tabindex="-1">Alias de permisos del grupo <a class="header-anchor" href="#alias-de-permisos-del-grupo" aria-label="Permalink to &quot;Alias de permisos del grupo&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th></tr></thead><tbody><tr><td><code>chmod_g+x</code></td><td>Añadir ejecución para el grupo</td></tr><tr><td><code>chmod_g-x</code></td><td>Quitar ejecución para el grupo</td></tr><tr><td><code>chmod_g+w</code></td><td>Añadir escritura para el grupo</td></tr><tr><td><code>chmod_g-w</code></td><td>Quitar escritura para el grupo</td></tr><tr><td><code>chmod_g+r</code></td><td>Añadir lectura para el grupo</td></tr><tr><td><code>chmod_g-r</code></td><td>Quitar lectura para el grupo</td></tr></tbody></table><h3 id="alias-de-permisos-para-otros" tabindex="-1">Alias de permisos para otros <a class="header-anchor" href="#alias-de-permisos-para-otros" aria-label="Permalink to &quot;Alias de permisos para otros&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th></tr></thead><tbody><tr><td><code>chmod_o+x</code></td><td>Añadir ejecución para otros</td></tr><tr><td><code>chmod_o-x</code></td><td>Quitar ejecución para otros</td></tr><tr><td><code>chmod_o+w</code></td><td>Añadir escritura para otros</td></tr><tr><td><code>chmod_o-w</code></td><td>Quitar escritura para otros</td></tr><tr><td><code>chmod_o+r</code></td><td>Añadir lectura para otros</td></tr><tr><td><code>chmod_o-r</code></td><td>Quitar lectura para otros</td></tr></tbody></table><h3 id="alias-por-tipo-de-archivo" tabindex="-1">Alias por tipo de archivo <a class="header-anchor" href="#alias-por-tipo-de-archivo" aria-label="Permalink to &quot;Alias por tipo de archivo&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Alias</th><th>Descripción</th></tr></thead><tbody><tr><td><code>chmod_755d</code></td><td>Establecer permisos de directorios a <code>rwxr-xr-x</code></td></tr><tr><td><code>chmod_644f</code></td><td>Establecer permisos de archivos a <code>rw-r--r--</code></td></tr></tbody></table><h3 id="funcion-recursiva" tabindex="-1">Función recursiva <a class="header-anchor" href="#funcion-recursiva" aria-label="Permalink to &quot;Función recursiva&quot;">​</a></h3><p>La función <code>change_permission</code> aplica permisos de forma recursiva con confirmación:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">change_permission</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 755</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/directory</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -R</span></span></code></pre></div>',20)])])}const u=t(r,[["render",i]]);export{m as __pageData,u as default};
